108	// ============================================================================
109	// 全量索引引擎
110	// ============================================================================
111	
112	/// 全量索引引擎
113	///
114	/// 负责遍历项目目录中的所有源文件，并行解析并提取符号信息，
115	/// 然后将结果批量写入 tantivy 全文索引和 sled 键值存储。
116	///
117	/// # 使用示例
118	///
119	/// ```ignore
120	/// let mut registry = Arc::new(ParserRegistry::new());
121	/// // ... 注册解析器 ...
122	/// let tantivy = TantivyIndex::open_or_create(index_dir)?;
123	/// let sled = SledStore::open(sled_dir)?;
124	/// let indexer = FullIndexer::new(project_root, tantivy, sled, registry);
125	/// let stats = indexer.run()?;
126	/// println!("索引完成: {:?}", stats);
127	/// ```
128	pub struct FullIndexer {
129	    /// 项目根目录
130	    project_root: PathBuf,
131	    /// tantivy 全文搜索索引
132	    tantivy: TantivyIndex,
133	    /// sled 键值存储
134	    sled: SledStore,
135	    /// 解析器注册表
136	    parser_registry: Arc<ParserRegistry>,
137	}
138	
139	impl FullIndexer {
140	    /// 创建全量索引器
141	    ///
142	    /// # 参数
143	    /// - `project_root` — 项目根目录路径
144	    /// - `tantivy` — 已初始化的 tantivy 索引实例
145	    /// - `sled` — 已打开的 sled 存储实例
146	    /// - `parser_registry` — 已注册所有语言解析器的注册表
147	    pub fn new(
148	        project_root: &Path,
149	        tantivy: TantivyIndex,
150	        sled: SledStore,
151	        parser_registry: Arc<ParserRegistry>,
152	    ) -> Self {
153	        Self {
154	            project_root: project_root.to_path_buf(),
155	            tantivy,
156	            sled,
157	            parser_registry,
158	        }
159	    }
160	
161	    /// 运行全量索引
162	    ///
163	    /// 这是索引引擎的主入口，执行完整的索引流程：
164	    /// 文件收集 → 并行解析 → 批量写入 → 提交刷盘
165	    ///
166	    /// # 返回
167	    /// 返回 [`IndexStats`] 包含详细的统计信息。
168	    pub fn run(&self) -> Result<IndexStats, CodeConnectError> {
169	        // ====================================================================
170	        // 第一步：收集需要解析的文件列表
171	        // ====================================================================
172	        let files = self.collect_files()?;
173	        let files_scanned = files.len() as u64;
174	
175	        tracing::info!("扫描完成，共发现 {} 个源文件", files_scanned);
176	
177	        if files.is_empty() {
178	            return Ok(IndexStats {
179	                files_scanned: 0,
180	                files_parsed: 0,
181	                symbols_found: 0,
182	                calls_found: 0,
183	                imports_found: 0,
184	                failed_files: Vec::new(),
185	            });
186	        }
187	
188	        // ====================================================================
189	        // 第二步：使用 rayon 并行解析所有文件
190	        // 通过 crossbeam channel 收集解析结果和失败信息
191	        // ====================================================================
192	        let (success_tx, success_rx) = channel::unbounded::<ParsedFile>();
193	        let (failure_tx, failure_rx) = channel::unbounded::<ParseFailure>();
194	
195	        let project_root = Arc::new(self.project_root.clone());
196	        let parser_registry = Arc::clone(&self.parser_registry);
197	
198	        files.par_iter().for_each(|file_path| {
199	            match parse_single_file(file_path, &parser_registry, &project_root) {
200	                Ok(parsed) => {
201	                    let _ = success_tx.send(parsed);
202	                }
203	                Err(error) => {
204	                    let _ = failure_tx.send(ParseFailure {
205	                        file_path: file_path.clone(),
206	                        error,
207	                    });
208	                }
209	            }
210	        });
211	
212	        // 关闭发送端，以便接收端的迭代可以自然结束
213	        drop(success_tx);
214	        drop(failure_tx);
215	
216	        // ====================================================================
217	        // 第三步：收集结果并批量写入存储
218	        // ====================================================================
219	        let mut files_parsed: u64 = 0;
220	        let mut symbols_found: u64 = 0;
221	        let mut calls_found: u64 = 0;
222	        let mut imports_found: u64 = 0;
223	        let mut failed_files: Vec<String> = Vec::new();
224	
225	        // 按文件收集符号 ID 列表，用于写文件→符号映射
226	        let mut file_symbol_map: HashMap<String, FileIndexStats> = HashMap::new();
227	
228	        for parsed in success_rx {
229	            let relative_path = parsed.relative_path.clone();
230	            let stats = parsed.stats;
231	
232	            // 写入 sled 和 tantivy
233	            self.write_parsed_file(&parsed)?;
234	
235	            files_parsed += 1;
236	            symbols_found += stats.symbols;
237	            calls_found += stats.calls;
238	            imports_found += stats.imports;
239	
240	            file_symbol_map.insert(relative_path, stats);
241	        }
242	
243	        // 收集解析失败的文件
244	        for failure in failure_rx {
245	            failed_files.push(format!(
246	                "{}: {}",
247	                failure.file_path.display(),
248	                failure.error
249	            ));
250	        }
251	
252	        // ====================================================================
253	        // 第四步：提交 tantivy 写入
254	        // ====================================================================
255	        self.tantivy.commit()?;
256	
257	        // ====================================================================
258	        // 第五步：写入 Schema 版本并刷盘
259	        // ====================================================================
260	        self.sled.put_schema_version(CURRENT_SCHEMA_VERSION)?;
261	        self.sled.flush()?;
262	
263	        tracing::info!(
264	            "全量索引完成: {} 成功 / {} 失败, {} 符号, {} 调用, {} 导入",
265	            files_parsed,
266	            failed_files.len(),
267	            symbols_found,
268	            calls_found,
269	            imports_found
270	        );
271	
272	        Ok(IndexStats {
273	            files_scanned,
274	            files_parsed,
275	            symbols_found,
276	            calls_found,
277	            imports_found,
278	            failed_files,
279	        })
280	    }
281	
282	    /// 收集项目目录下的所有源文件
283	    ///
284	    /// 使用 `ignore::WalkBuilder` 遍历目录树，自动应用
285	    /// `.gitignore` 规则过滤，仅收集支持的编程语言源文件。
286	    fn collect_files(&self) -> Result<Vec<PathBuf>, CodeConnectError> {
287	        let mut files = Vec::new();
288	
289	        let walker = WalkBuilder::new(&self.project_root)
290	            .standard_filters(true) // 自动 .gitignore 与常见忽略规则
291	            .hidden(false) // 不跳过隐藏文件（某些配置目录需要处理）
292	            .build();
293	
294	        for entry in walker {
295	            let entry = entry
296	                .map_err(|e| CodeConnectError::Index(format!("目录遍历失败: {}", e)))?;
297	
298	            // 只处理普通文件
299	            if !entry.file_type().map_or(false, |ft| ft.is_file()) {
300	                continue;
301	            }
302	
303	            let path = entry.path();
304	
305	            // 按扩展名过滤支持的编程语言
306	            if let Some(ext) = path.extension().and_then(|e| e.to_str()) {
307	                let supported = matches!(
308	                    ext,
309	                    "rs" | "ts" | "tsx" | "js" | "jsx" | "mjs" | "cjs" | "java" | "cs"
310	                );
311	                if supported {
312	                    files.push(path.to_path_buf());
313	                }
314	            }
315	        }
316	
317	        // 按路径排序以保证索引顺序稳定
318	        files.sort();
319	
320	        Ok(files)
321	    }
322	
323	    /// 将单个文件的解析结果写入存储
324	    ///
325	    /// 包括：文件元信息、符号定义、文件指纹、文件→符号映射，
326	    /// 以及将每个符号写入 tantivy 全文索引。
327	    fn write_parsed_file(&self, parsed: &ParsedFile) -> Result<(), CodeConnectError> {
328	        let file_path_str = &parsed.relative_path;
329	
330	        // ---- 写入文件元信息 ----
331	        let file_meta = FileMeta {
332	            file_path: file_path_str.clone(),
333	            language: parsed.language.to_string(),
334	            content_hash: parsed.content_hash.clone(),
335	            symbol_count: parsed.symbols.len() as u64,
336	            indexed_at: SystemTime::now()
337	                .duration_since(SystemTime::UNIX_EPOCH)
338	                .unwrap_or_default()
339	                .as_secs() as i64,
340	        };
341	
342	        let meta_bytes = serde_json::to_vec(&file_meta)
343	            .map_err(|e| CodeConnectError::Index(format!("序列化文件元信息失败: {}", e)))?;
344	        self.sled.put_file_meta(file_path_str, &meta_bytes)?;
345	
346	        // ---- 收集文件内所有符号 ID ----
347	        let mut file_symbol_ids: Vec<String> = Vec::with_capacity(parsed.symbols.len());
348	
349	        // ---- 写入每个符号定义 ----
350	        for symbol in &parsed.symbols {
351	            file_symbol_ids.push(symbol.id.clone());
352	
353	            let sym_bytes = serde_json::to_vec(symbol)
354	                .map_err(|e| CodeConnectError::Index(format!("序列化符号失败: {}", e)))?;
355	            self.sled.put_symbol(&symbol.id, &sym_bytes)?;
356	
357	            // ---- 写入 tantivy 全文索引 ----
358	            Self::add_symbol_to_tantivy(&self.tantivy, symbol, parsed, file_path_str)?;
359	        }
360	
361	        // ---- 写入文件→符号映射 ----
362	        let file_symbol_bytes = serde_json::to_vec(&file_symbol_ids)
363	            .map_err(|e| CodeConnectError::Index(format!("序列化文件符号映射失败: {}", e)))?;
364	        self.sled
365	            .put_file_symbols(file_path_str, &file_symbol_bytes)?;
366	
367	        // ---- 写入文件指纹 ----
368	        self.sled
369	            .put_fingerprint(file_path_str, parsed.content_hash.as_bytes())?;
370	
371	        Ok(())
372	    }
373	
374	    /// 将单个符号添加到 tantivy 全文索引
375	    fn add_symbol_to_tantivy(
376	        tantivy: &TantivyIndex,
377	        symbol: &codeconnect_core::types::Symbol,
378	        parsed: &ParsedFile,
379	        file_path_str: &str,
380	    ) -> Result<(), CodeConnectError> {
381	        // 将 SymbolKind 枚举映射为字符串
382	        let kind_str = match &symbol.kind {
383	            SymbolKind::Function => "function",
384	            SymbolKind::Method => "method",
385	            SymbolKind::Class => "class",
386	            SymbolKind::Interface => "interface",
387	            SymbolKind::Struct => "struct",
388	            SymbolKind::Enum => "enum",
389	            SymbolKind::Trait => "trait",
390	            SymbolKind::TypeAlias => "type_alias",
391	            SymbolKind::Variable => "variable",
392	            SymbolKind::Field => "field",
393	            SymbolKind::Module => "module",
394	            SymbolKind::Macro => "macro",
395	            SymbolKind::Parameter => "parameter",
396	            SymbolKind::Unknown(_) => "unknown",
397	        };
398	
399	        // 修饰符列表以逗号+空格拼接
400	        let modifiers_str = symbol.modifiers.join(", ");
401	
402	        tantivy.add_symbol(
403	            &symbol.id,
404	            &symbol.name,
405	            kind_str,
406	            parsed.language,
407	            file_path_str,
408	            symbol.signature.as_deref().unwrap_or(""),
409	            symbol.doc_comment.as_deref().unwrap_or(""),
410	            "", // definition — 暂不在解析器中提取
411	            "", // body_text — 暂不在解析器中提取
412	            symbol.parent_id.as_deref().unwrap_or(""),
413	            &modifiers_str,
414	            symbol.complexity.unwrap_or(0),
415	            "", // ast_hash — 暂不在此阶段计算
416	            symbol.is_exported,
417	        )
418	    }
419	}
420	
421	// ============================================================================
422	// 并行解析辅助函数
423	// ============================================================================
424	
425	/// 解析单个文件并提取所有结构化信息
426	///
427	/// 此函数设计为可在 rayon 并行迭代中调用，无外部可变依赖。
428	/// 所有数据通过返回值传递，由主线程统一写入存储。
429	fn parse_single_file(
430	    file_path: &Path,
431	    parser_registry: &Arc<ParserRegistry>,
432	    project_root: &Path,
433	) -> Result<ParsedFile, String> {
434	    // 查找对应的解析器
435	    let parser = parser_registry
436	        .get_for_file(file_path)
437	        .ok_or_else(|| format!("不支持的文件类型: {}", file_path.display()))?;
438	
439	    let language: &'static str = parser.language();
440	
441	    // 读取文件内容
442	    let source = std::fs::read_to_string(file_path)
443	        .map_err(|e| format!("读取文件失败 {}: {}", file_path.display(), e))?;
444	
445	    // 计算内容哈希
446	    let hash = blake3::hash(source.as_bytes());
447	    let content_hash = hash.to_hex().to_string();
448	
449	    // 计算相对于项目根目录的路径
450	    let relative_path = file_path
451	        .strip_prefix(project_root)
452	        .unwrap_or(file_path)
453	        .to_string_lossy()
454	        .to_string();
455	
456	    // 解析源码为 AST
457	    let tree = parser
458	        .parse(&source)
459	        .map_err(|e| format!("解析失败 {}: {}", file_path.display(), e))?;
460	
461	    // 提取符号
462	    let symbols = parser.extract_symbols(&tree, &source, file_path);
463	
464	    // 提取调用
465	    let calls = parser.extract_calls(&tree, &source, file_path);
466	
467	    // 提取导入
468	    let imports = parser.extract_imports(&tree, &source, file_path);
469	
470	    let stats = FileIndexStats {
471	        symbols: symbols.len() as u64,
472	        calls: calls.len() as u64,
473	        imports: imports.len() as u64,
474	    };
475	
476	    Ok(ParsedFile {
477	        file_path: file_path.to_path_buf(),
478	        relative_path,
479	        source,
480	        content_hash,
481	        language,
482	        symbols,
483	        calls,
484	        imports,
485	        stats,
486	    })
487	}
488	
489	// ============================================================================
490	// 测试
491	// ============================================================================
492	
493	#[cfg(test)]
494	mod tests {
495	    use super::*;
496	
497	    /// 测试空项目（无源文件）不会出错
498	    #[test]
499	    fn test_collect_files_empty_dir() {
500	        let tmp = std::env::temp_dir().join("codeconnect_test_empty");
501	        let _ = std::fs::create_dir_all(&tmp);
502	
503	        // 这里只验证遍历逻辑不会在空目录崩溃
504	        // 注意：需要实际的索引实例，所以此处仅验证 collect_files 的逻辑模式
505	        assert!(tmp.exists());
506	
507	        let _ = std::fs::remove_dir_all(&tmp);
508	    }
509	
510	    /// 测试 FileIndexStats::merge 合并逻辑
511	    #[test]
512	    fn test_file_index_stats_merge() {
513	        let s1 = FileIndexStats {
514	            symbols: 10,
515	            calls: 5,
516	            imports: 2,
517	        };
518	        let s2 = FileIndexStats {
519	            symbols: 20,
520	            calls: 8,
521	            imports: 3,
522	        };
523	        let s3 = FileIndexStats::default();
524	
525	        let merged = FileIndexStats::merge(&[s1, s2, s3]);
526	        assert_eq!(merged.symbols, 30);
527	        assert_eq!(merged.calls, 13);
528	        assert_eq!(merged.imports, 5);
529	    }
530	}
