48	        let end = node.end_position();
49	        SourceLocation {
50	            file_path: String::new(), // 由外部调用者填充
51	            line: start.row as u64 + 1,
52	            column: start.column as u64 + 1,
53	            end_line: end.row as u64 + 1,
