351	    fn infer_package(&self, file_path: &Path, _source: &str) -> Option<String> {
352	        // Rust 项目：从文件路径的目录结构中推断 crate 名
353	        // 遍历路径组件，跳过 "src" 目录，取第一个正常目录名
354	        let components: Vec<_> = file_path.components().collect();
355	        for component in components.iter().rev() {
356	            if let std::path::Component::Normal(name) = component {
357	                let name_str = name.to_str().unwrap_or("");
358	                if name_str == "src" {
359	                    continue;
360	                }
361	                if !name_str.is_empty() {
362	                    return Some(name_str.to_string());
363	                }
364	            }
365	        }
366	        None
367	    }
368	}
