160	    /// 文件收集 → 并行解析 → 批量写入 → 提交刷盘
161	    ///
162	    /// # 返回
163	    /// 返回 [`IndexStats`] 包含详细的统计信息。
164	    pub fn run(&self) -> Result<IndexStats, CodeConnectError> {
165	        // ====================================================================
166	        // 第一步：收集需要解析的文件列表
167	        // ====================================================================
168	        let files = self.collect_files()?;
169	        let files_scanned = files.len() as u64;
170	
171	        tracing::info!("扫描完成，共发现 {} 个源文件", files_scanned);
172	
173	        if files.is_empty() {
174	            return Ok(IndexStats {
175	                files_scanned: 0,
176	                files_parsed: 0,
177	                symbols_found: 0,
178	                calls_found: 0,
179	                imports_found: 0,
180	                failed_files: Vec::new(),
181	            });
182	        }
183	
184	        // ====================================================================
185	        // 第二步：使用 rayon 并行解析所有文件
186	        // 通过 crossbeam channel 收集解析结果和失败信息
187	        // ====================================================================
188	        let (success_tx, success_rx) = channel::unbounded::<ParsedFile>();
189	        let (failure_tx, failure_rx) = channel::unbounded::<ParseFailure>();
190	
191	        let project_root = Arc::new(self.project_root.clone());
192	        let parser_registry = Arc::clone(&self.parser_registry);
193	
194	        files.par_iter().for_each(|file_path| {
195	            match parse_single_file(file_path, &parser_registry, &project_root) {
196	                Ok(parsed) => {
197	                    let _ = success_tx.send(parsed);
198	                }
199	                Err(error) => {
200	                    let _ = failure_tx.send(ParseFailure {
201	                        file_path: file_path.clone(),
202	                        error,
203	                    });
204	                }
205	            }
206	        });
207	
208	        // 关闭发送端，以便接收端的迭代可以自然结束
209	        drop(success_tx);
210	        drop(failure_tx);
211	
212	        // ====================================================================
213	        // 第三步：收集结果并批量写入存储
214	        // ====================================================================
215	        let mut files_parsed: u64 = 0;
216	        let mut symbols_found: u64 = 0;
217	        let mut calls_found: u64 = 0;
218	        let mut imports_found: u64 = 0;
219	        let mut failed_files: Vec<String> = Vec::new();
220	
221	        // 按文件收集符号 ID 列表，用于写文件→符号映射
222	        let mut file_symbol_map: HashMap<String, FileIndexStats> = HashMap::new();
223	
224	        for parsed in success_rx {
225	            let relative_path = parsed.relative_path.clone();
226	            // 先统计再写入，避免 parsed 部分移动后无法借用
227	            let symbols_count = parsed.stats.symbols;
228	            let calls_count = parsed.stats.calls;
229	            let imports_count = parsed.stats.imports;
230	
231	            // 写入 sled 和 tantivy
232	            self.write_parsed_file(&parsed)?;
233	
234	            files_parsed += 1;
235	            symbols_found += symbols_count;
236	            calls_found += calls_count;
237	            imports_found += imports_count;
238	
239	            file_symbol_map.insert(relative_path, parsed.stats);
240	        }
241	
242	        // 收集解析失败的文件
243	        for failure in failure_rx {
244	            failed_files.push(format!(
245	                "{}: {}",
246	                failure.file_path.display(),
247	                failure.error
248	            ));
249	        }
250	
251	        // ====================================================================
252	        // 第四步：提交 tantivy 写入
253	        // ====================================================================
254	        self.tantivy.commit()?;
255	
256	        // ====================================================================
257	        // 第五步：写入 Schema 版本并刷盘
258	        // ====================================================================
259	        self.sled.put_schema_version(CURRENT_SCHEMA_VERSION)?;
260	        self.sled.flush()?;
261	
262	        tracing::info!(
263	            "全量索引完成: {} 成功 / {} 失败, {} 符号, {} 调用, {} 导入",
264	            files_parsed,
265	            failed_files.len(),
266	            symbols_found,
267	            calls_found,
268	            imports_found
269	        );
270	
271	        Ok(IndexStats {
272	            files_scanned,
273	            files_parsed,
274	            symbols_found,
275	            calls_found,
276	            imports_found,
277	            failed_files,
278	        })
279	    }
280	
281	    /// 收集项目目录下的所有源文件
282	    ///
283	    /// 使用 `ignore::WalkBuilder` 遍历目录树，自动应用
284	    /// `.gitignore` 规则过滤，仅收集支持的编程语言源文件。
285	    fn collect_files(&self) -> Result<Vec<PathBuf>, CodeConnectError> {
286	        let mut files = Vec::new();
287	
288	        let walker = WalkBuilder::new(&self.project_root)
289	            .standard_filters(true) // 自动 .gitignore 与常见忽略规则
290	            .hidden(false) // 不跳过隐藏文件（某些配置目录需要处理）
291	            .build();
292	
293	        for entry in walker {
294	            let entry = entry
295	                .map_err(|e| CodeConnectError::Index(format!("目录遍历失败: {}", e)))?;
296	
297	            // 只处理普通文件
298	            if !entry.file_type().map_or(false, |ft| ft.is_file()) {
299	                continue;
300	            }
301	
302	            let path = entry.path();
303	
304	            // 按扩展名过滤支持的编程语言
305	            if let Some(ext) = path.extension().and_then(|e| e.to_str()) {
306	                let supported = matches!(
307	                    ext,
308	                    "rs" | "ts" | "tsx" | "js" | "jsx" | "mjs" | "cjs" | "java" | "cs"
309	                );
310	                if supported {
311	                    files.push(path.to_path_buf());
312	                }
313	            }
314	        }
315	
316	        // 按路径排序以保证索引顺序稳定
317	        files.sort();
318	
319	        Ok(files)
320	    }
321	
322	    /// 将单个文件的解析结果写入存储
323	    ///
324	    /// 包括：文件元信息、符号定义、文件指纹、文件→符号映射，
325	    /// 以及将每个符号写入 tantivy 全文索引。
326	    fn write_parsed_file(&self, parsed: &ParsedFile) -> Result<(), CodeConnectError> {
327	        let file_path_str = &parsed.relative_path;
328	
329	        // ---- 写入文件元信息 ----
330	        let file_meta = FileMeta {
331	            file_path: file_path_str.clone(),
332	            language: parsed.language.to_string(),
333	            content_hash: parsed.content_hash.clone(),
334	            symbol_count: parsed.symbols.len() as u64,
335	            indexed_at: SystemTime::now()
336	                .duration_since(SystemTime::UNIX_EPOCH)
337	                .unwrap_or_default()
338	                .as_secs() as i64,
339	        };
340	
341	        let meta_bytes = serde_json::to_vec(&file_meta)
342	            .map_err(|e| CodeConnectError::Index(format!("序列化文件元信息失败: {}", e)))?;
343	        self.sled.put_file_meta(file_path_str, &meta_bytes)?;
344	
345	        // ---- 收集文件内所有符号 ID ----
346	        let mut file_symbol_ids: Vec<String> = Vec::with_capacity(parsed.symbols.len());
347	
348	        // ---- 写入每个符号定义 ----
349	        for symbol in &parsed.symbols {
350	            file_symbol_ids.push(symbol.id.clone());
351	
352	            let sym_bytes = serde_json::to_vec(symbol)
353	                .map_err(|e| CodeConnectError::Index(format!("序列化符号失败: {}", e)))?;
354	            self.sled.put_symbol(&symbol.id, &sym_bytes)?;
355	
356	            // ---- 写入 tantivy 全文索引 ----
357	            Self::add_symbol_to_tantivy(&self.tantivy, symbol, parsed, file_path_str)?;
358	        }
359	
360	        // ---- 写入文件→符号映射 ----
361	        let file_symbol_bytes = serde_json::to_vec(&file_symbol_ids)
362	            .map_err(|e| CodeConnectError::Index(format!("序列化文件符号映射失败: {}", e)))?;
363	        self.sled
364	            .put_file_symbols(file_path_str, &file_symbol_bytes)?;
365	
366	        // ---- 写入文件指纹 ----
367	        self.sled
368	            .put_fingerprint(file_path_str, parsed.content_hash.as_bytes())?;
369	
370	        Ok(())
371	    }
372	
373	    /// 将单个符号添加到 tantivy 全文索引
374	    fn add_symbol_to_tantivy(
375	        tantivy: &TantivyIndex,
376	        symbol: &codeconnect_core::types::Symbol,
377	        parsed: &ParsedFile,
378	        file_path_str: &str,
379	    ) -> Result<(), CodeConnectError> {
380	        // 将 SymbolKind 枚举映射为字符串
381	        let kind_str = match &symbol.kind {
382	            SymbolKind::Function => "function",
383	            SymbolKind::Method => "method",
384	            SymbolKind::Class => "class",
385	            SymbolKind::Interface => "interface",
386	            SymbolKind::Struct => "struct",
387	            SymbolKind::Enum => "enum",
388	            SymbolKind::Trait => "trait",
389	            SymbolKind::TypeAlias => "type_alias",
390	            SymbolKind::Variable => "variable",
391	            SymbolKind::Field => "field",
392	            SymbolKind::Module => "module",
393	            SymbolKind::Macro => "macro",
394	            SymbolKind::Parameter => "parameter",
395	            SymbolKind::Unknown(_) => "unknown",
396	        };
397	
398	        // 修饰符列表以逗号+空格拼接
399	        let modifiers_str = symbol.modifiers.join(", ");
400	
401	        tantivy.add_symbol(
402	            &symbol.id,
403	            &symbol.name,
404	            kind_str,
405	            parsed.language,
406	            file_path_str,
407	            symbol.signature.as_deref().unwrap_or(""),
408	            symbol.doc_comment.as_deref().unwrap_or(""),
409	            "", // definition — 暂不在解析器中提取
410	            "", // body_text — 暂不在解析器中提取
411	            symbol.parent_id.as_deref().unwrap_or(""),
412	            &modifiers_str,
413	            symbol.complexity.unwrap_or(0),
414	            "", // ast_hash — 暂不在此阶段计算
415	            symbol.is_exported,
416	        )
417	    }
418	}
419	
420	// ============================================================================
421	// 并行解析辅助函数
422	// ============================================================================
423	
424	/// 解析单个文件并提取所有结构化信息
425	///
426	/// 此函数设计为可在 rayon 并行迭代中调用，无外部可变依赖。
427	/// 所有数据通过返回值传递，由主线程统一写入存储。
428	fn parse_single_file(
429	    file_path: &Path,
430	    parser_registry: &Arc<ParserRegistry>,
431	    project_root: &Path,
432	) -> Result<ParsedFile, String> {
433	    // 查找对应的解析器
434	    let parser = parser_registry
435	        .get_for_file(file_path)
436	        .ok_or_else(|| format!("不支持的文件类型: {}", file_path.display()))?;
437	
438	    let language: &'static str = parser.language();
439	
440	    // 读取文件内容
441	    let source = std::fs::read_to_string(file_path)
442	        .map_err(|e| format!("读取文件失败 {}: {}", file_path.display(), e))?;
443	
444	    // 计算内容哈希（blake3::Hash 实现了 Display，输出十六进制字符串）
445	    let content_hash = blake3::hash(source.as_bytes()).to_string();
446	
447	    // 计算相对于项目根目录的路径
448	    let relative_path = file_path
449	        .strip_prefix(project_root)
450	        .unwrap_or(file_path)
451	        .to_string_lossy()
452	        .to_string();
453	
454	    // 解析源码为 AST
455	    let tree = parser
456	        .parse(&source)
457	        .map_err(|e| format!("解析失败 {}: {}", file_path.display(), e))?;
458	
459	    // 提取符号
460	    let symbols = parser.extract_symbols(&tree, &source, file_path);
461	
462	    // 提取调用
463	    let calls = parser.extract_calls(&tree, &source, file_path);
464	
465	    // 提取导入
466	    let imports = parser.extract_imports(&tree, &source, file_path);
467	
468	    let stats = FileIndexStats {
469	        symbols: symbols.len() as u64,
470	        calls: calls.len() as u64,
471	        imports: imports.len() as u64,
472	    };
473	
474	    Ok(ParsedFile {
475	        relative_path,
476	        content_hash,
477	        language,
478	        symbols,
479	        calls,
480	        imports,
481	        stats,
482	    })
483	}
484	
485	// ============================================================================
486	// 测试
487	// ============================================================================
488	
489	#[cfg(test)]
490	mod tests {
491	    use super::*;
492	
493	    /// 测试空项目（无源文件）不会出错
494	    #[test]
495	    fn test_collect_files_empty_dir() {
496	        let tmp = std::env::temp_dir().join("codeconnect_test_empty");
497	        let _ = std::fs::create_dir_all(&tmp);
498	
499	        // 这里只验证遍历逻辑不会在空目录崩溃
500	        // 注意：需要实际的索引实例，所以此处仅验证 collect_files 的逻辑模式
501	        assert!(tmp.exists());
502	
503	        let _ = std::fs::remove_dir_all(&tmp);
504	    }
505	
506	    /// 测试 FileIndexStats::merge 合并逻辑
507	    #[test]
508	    fn test_file_index_stats_merge() {
509	        let s1 = FileIndexStats {
510	            symbols: 10,
511	            calls: 5,
512	            imports: 2,
513	        };
514	        let s2 = FileIndexStats {
515	            symbols: 20,
516	            calls: 8,
517	            imports: 3,
518	        };
519	        let s3 = FileIndexStats::default();
520	
521	        let merged = FileIndexStats::merge(&[s1, s2, s3]);
522	        assert_eq!(merged.symbols, 30);
523	        assert_eq!(merged.calls, 13);
524	        assert_eq!(merged.imports, 5);
525	    }
526	}
