            calls: 5,
            imports: 2,
        };
        let s2 = FileIndexStats {
            symbols: 20,
            calls: 8,
            imports: 3,
        };
        let s3 = FileIndexStats::default();

        let merged = FileIndexStats::merge(&[s1, s2, s3]);
        assert_eq!(merged.symbols, 30);
        assert_eq!(merged.calls, 13);
        assert_eq!(merged.imports, 5);
    }
}

